import{_ as i,c as a,o as t,ag as e}from"./chunks/framework.GdcW6lnn.js";const c=JSON.parse('{"title":"SCSS @import Directive","description":"","frontmatter":{},"headers":[],"relativePath":"basics_scss/scss-import.md","filePath":"basics_scss/scss-import.md"}'),p={name:"basics_scss/scss-import.md"};function n(l,s,h,o,r,d){return t(),a("div",null,s[0]||(s[0]=[e(`<h1 id="scss-import-directive" tabindex="-1">SCSS @import Directive <a class="header-anchor" href="#scss-import-directive" aria-label="Permalink to “SCSS @import Directive”">​</a></h1><p>Директива <code>@import</code> в SCSS используется для включения содержимого одного SCSS файла в другой. Это позволяет разбивать ваш CSS на более мелкие, управляемые файлы и затем объединять их в один скомпилированный CSS файл.</p><h2 id="базовое-использование" tabindex="-1">Базовое использование <a class="header-anchor" href="#базовое-использование" aria-label="Permalink to “Базовое использование”">​</a></h2><p>Простейший способ использования <code>@import</code> - указать путь к файлу, который вы хотите импортировать. По умолчанию SCSS предполагает, что импортируемый файл является другим SCSS файлом (<code>.scss</code> или <code>.sass</code>).</p><p><strong>Синтаксис:</strong></p><div class="language-scss vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">scss</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;path/to/file&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p><strong>Пример:</strong></p><p>Предположим, у вас есть файл <code>_variables.scss</code> (обратите внимание на символ <code>_</code> в начале имени файла - это соглашение об именовании для partials, которые не должны компилироваться в отдельный CSS файл):</p><div class="language-scss vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">scss</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// _variables.scss</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">$primary-color</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">blue</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">$font-size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">px</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>И вы хотите использовать эти переменные в вашем основном файле <code>style.scss</code>:</p><div class="language-scss vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">scss</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// style.scss</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;variables&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// SCSS автоматически ищет файлы с расширениями .scss или .sass</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">body</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  color</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">$primary-color</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  font-size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">$font-size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>При компиляции <code>style.scss</code> содержимое <code>_variables.scss</code> будет включено в результирующий <code>style.css</code>.</p><h2 id="partial-imports" tabindex="-1">Partial Imports <a class="header-anchor" href="#partial-imports" aria-label="Permalink to “Partial Imports”">​</a></h2><p>Часто вы будете создавать SCSS файлы, содержащие только фрагменты стилей (например, переменные, mixins, functions), которые не должны компилироваться в отдельные CSS файлы. По соглашению, такие файлы начинаются с символа подчеркивания <code>_</code> (например, <code>_variables.scss</code>, <code>_mixins.scss</code>).</p><p>При использовании <code>@import</code> вам <strong>не нужно</strong> указывать подчеркивание и расширение файла для partials. SCSS автоматически найдет файл.</p><p><strong>Пример:</strong></p><div class="language-scss vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">scss</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;variables&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Импортирует _variables.scss</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;mixins&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Импортирует _mixins.scss</span></span></code></pre></div><h2 id="css-imports" tabindex="-1">CSS Imports <a class="header-anchor" href="#css-imports" aria-label="Permalink to “CSS Imports”">​</a></h2><p>Если вы хотите импортировать обычный CSS файл (<code>.css</code>), SCSS обработает это как обычный CSS <code>@import</code> и оставит его как есть в скомпилированном CSS файле. Это полезно для включения сторонних библиотек или CSS файлов, которые вы не хотите компилировать через SCSS.</p><p><strong>Синтаксис:</strong></p><div class="language-scss vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">scss</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;path/to/style.css&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p><strong>Пример:</strong></p><div class="language-scss vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">scss</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;normalize.css&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// В результирующем CSS останется @import &quot;normalize.css&quot;;</span></span></code></pre></div><h2 id="медиа-запросы-в-imports" tabindex="-1">Медиа-запросы в Imports <a class="header-anchor" href="#медиа-запросы-в-imports" aria-label="Permalink to “Медиа-запросы в Imports”">​</a></h2><p>Вы можете применять медиа-запросы к импортированным стилям. Импортированные стили будут включены только при выполнении указанного медиа-условия.</p><p><strong>Синтаксис:</strong></p><div class="language-scss vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">scss</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;path/to/file&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> screen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> and</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">min-width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">768px</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p><strong>Пример:</strong></p><div class="language-scss vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">scss</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;mobile-styles&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">max-width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">767px</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;desktop-styles&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> screen</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> and</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">min-width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">768px</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><h2 id="указание-нескольких-фаилов-для-импорта" tabindex="-1">Указание нескольких файлов для импорта <a class="header-anchor" href="#указание-нескольких-фаилов-для-импорта" aria-label="Permalink to “Указание нескольких файлов для импорта”">​</a></h2><p>Вы можете импортировать несколько файлов одновременно, перечислив их через запятую.</p><p><strong>Синтаксис:</strong></p><div class="language-scss vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">scss</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;variables&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mixins&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;theme&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h2 id="правила-import" tabindex="-1">Правила <code>@import</code> <a class="header-anchor" href="#правила-import" aria-label="Permalink to “Правила @import”">​</a></h2><ul><li>Все директивы <code>@import</code> должны располагаться в начале SCSS файла, перед любыми правилами стилей.</li><li>SCSS будет искать импортируемые файлы в текущем каталоге и в путях, указанных в настройках компилятора (load paths).</li></ul><h2 id="преимущества-использования-import" tabindex="-1">Преимущества использования <code>@import</code> <a class="header-anchor" href="#преимущества-использования-import" aria-label="Permalink to “Преимущества использования @import”">​</a></h2><ul><li><strong>Организация кода:</strong> Разбиение стилей на логические файлы делает код более структурированным и легким в поддержке.</li><li><strong>Переиспользование кода:</strong> Переменные, mixins и functions могут быть определены в одном файле и импортированы во многие другие.</li><li><strong>Улучшение читаемости:</strong> Меньшие файлы легче читать и понимать.</li></ul><h2 id="недостатки-по-сравнению-с-use-и-forward-в-современных-версиях-scss" tabindex="-1">Недостатки (по сравнению с <code>@use</code> и <code>@forward</code> в современных версиях SCSS) <a class="header-anchor" href="#недостатки-по-сравнению-с-use-и-forward-в-современных-версиях-scss" aria-label="Permalink to “Недостатки (по сравнению с @use и @forward в современных версиях SCSS)”">​</a></h2><p>В более новых версиях SCSS (начиная с версии 1.3.0) рекомендуется использовать директивы <code>@use</code> и <code>@forward</code> вместо <code>@import</code>. <code>@import</code> имеет некоторые недостатки:</p><ul><li><strong>Глобальная область видимости:</strong> Переменные, mixins и functions, импортированные с помощью <code>@import</code>, становятся доступны глобально во всем файле, что может привести к конфликтам имен.</li><li><strong>Отсутствие контроля над импортируемым:</strong> Вы импортируете все содержимое файла, даже если вам нужна только часть.</li><li><strong>Повторный импорт:</strong> Один и тот же файл может быть импортирован несколько раз, что может привести к раздуванию CSS.</li></ul><p>Несмотря на эти недостатки, <code>@import</code> все еще поддерживается и широко используется в существующих проектах. Однако для новых проектов рекомендуется изучить и использовать <code>@use</code> и <code>@forward</code> для лучшей организации и производительности.</p><h2 id="заключение" tabindex="-1">Заключение <a class="header-anchor" href="#заключение" aria-label="Permalink to “Заключение”">​</a></h2><p>Директива <code>@import</code> является фундаментальным инструментом в SCSS для организации и включения стилей из других файлов. Понимание ее работы и правил поможет вам создавать более структурированные и поддерживаемые CSS проекты. Однако помните о преимуществах <code>@use</code> и <code>@forward</code> в современных версиях SCSS.</p>`,43)]))}const g=i(p,[["render",n]]);export{c as __pageData,g as default};
